import sys

def allocate_buffer(count, item_size):
    if count < 0 or item_size < 0:
        raise ValueError('Negative values not allowed')
    if count > 0 and item_size > sys.maxsize // count:
        raise OverflowError('Buffer size overflow')
    total = count * item_size
    return bytearray(total)
